class Solution:
    def solveEquation(self, equation: str) -> str:
        def parse_side(s):
            x_coeff = 0
            const = 0
            tokens = re.split('(?=[+-])', s)
            for token in tokens:
                if not token:
                    continue
                sign = token[0]
                term = token[1:]
                if term == 'x':
                    coeff = 1 if sign == '+' else -1
                    x_coeff += coeff
                elif 'x' in term:
                    coeff_part = term.replace('x', '')
                    if coeff_part == '':
                        coeff = 1
                    else:
                        coeff = int(coeff_part)
                    if sign == '-':
                        coeff = -coeff
                    x_coeff += coeff
                else:
                    if term == '':
                        continue
                    value = int(term)
                    if sign == '-':
                        value = -value
                    const += value
            return x_coeff, const

        left, right = equation.split('=')
        left_x, left_const = parse_side(left)
        right_x, right_const = parse_side(right)

        overall_x = left_x - right_x
        overall_const = right_const - left_const

        if overall_x == 0:
            if overall_const == 0:
                return "Infinite solutions"
            else:
                return "No solution"
        else:
            x = overall_const // overall_x
            return f"x={x}"
